chart.options:
chart: {
  height: 350,
  type: 'scatter',
  zoom: {
    enabled: true,
    type: 'xy'
  }
},
title: {
  text: 'Fuel Efficiency vs Engine Size'
},
xaxis: {
  tickAmount: 10,
  title: {
    text: 'Engine Size (L)'
  },
  labels: {
    formatter: function(val) {
      return parseFloat(val).toFixed(1)
    }
  }
},
yaxis: {
  tickAmount: 7,
  title: {
    text: 'Fuel Economy (mpg)'
  }
},
tooltip: {
  shared: false,
  intersect: true
},
